@startuml

interface Printer {
  + void print(Document)
}

interface Scanner {
  + void scan(Document)
}

class SimplePrinter {
  + void print(Document)
}

class SimplePrinterScanner {
  + void print(Document)
  + void scan(Document)
}

SimplePrinter ..|> Printer
SimplePrinterScanner ..|> Printer
SimplePrinterScanner ..|> Scanner

@enduml
